class MyChatLanguageModel implements LanguageModelV3 {
  readonly specificationVersion = 'v3';
  readonly modelId: string;
  readonly supportedUrls = {
    'image/*': [/^https?:\/\/.*$/],
    // Add other supported media types
  };

  private readonly config: ModelConfig;

  constructor(modelId: string, config: ModelConfig) {
    this.modelId = modelId;
    this.config = config;
  }

  get provider(): string {
    return this.config.provider;
  }

  // Parse provider-specific options using schema
  private async getArgs(options: LanguageModelV3CallOptions) {
    const warnings: SharedV3Warning[] = [];

    const myOptions = await parseProviderOptions({
      provider: 'myprovider',
      providerOptions: options.providerOptions,
      schema: myLanguageModelOptions, // Zod schema
    }) ?? {};

    // Map AI SDK standardized options to API-specific format
    // Handle unsupported features by adding warnings

    return { args: body, warnings };
  }

  // Non-streaming generation
  async doGenerate(options: LanguageModelV3CallOptions): Promise<LanguageModelV3GenerateResult> {
    const { args: body, warnings } = await this.getArgs(options);

    const { responseHeaders, value: response, rawValue } = await postJsonToApi({
      url: this.config.url({ path: '/chat/completions', modelId: this.modelId }),
      headers: combineHeaders(this.config.headers(), options.headers),
      body,
      failedResponseHandler: myFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(myResponseSchema),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    return {
      content: [{ type: 'text', text: response.content }],
      finishReason: { unified: 'stop', raw: response.finishReason },
      usage: { inputTokens: response.usage.input, outputTokens: response.usage.output },
      request: { body },
      response: { headers: responseHeaders, body: rawValue },
      warnings,
      providerMetadata: { myprovider: {} },
    };
  }

  // Streaming generation
  async doStream(options: LanguageModelV3CallOptions): Promise<LanguageModelV3StreamResult> {
    const { args, warnings } = await this.getArgs(options);

    const body = { ...args, stream: true };

    const { responseHeaders, value: response } = await postJsonToApi({
      url: this.config.url({ path: '/chat/completions', modelId: this.modelId }),
      headers: combineHeaders(this.config.headers(), options.headers),
      body,
      failedResponseHandler: myFailedResponseHandler,
      successfulResponseHandler: createEventSourceResponseHandler(myChunkSchema),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    return {
      stream: response.pipeThrough(
        new TransformStream<ParseResult<MyChunk>, LanguageModelV3StreamPart>({
          start(controller) {
            controller.enqueue({ type: 'stream-start', warnings });
          },
          transform(chunk, controller) {
            if (!chunk.success) {
              controller.enqueue({ type: 'error', error: chunk.error });
              return;
            }
            // Transform API chunks to SDK stream parts
            controller.enqueue({
              type: 'text-delta',
              textDelta: chunk.value.delta,
            });
          },
          flush(controller) {
            controller.enqueue({ type: 'stream-end' });
          },
        }),
      ),
    };
  }
}
