```typescript
// 1. Provider Settings Interface
export interface ProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
  name?: string; // custom provider name override
}

// 2. Provider Interface extending ProviderV3
export interface MyProvider extends ProviderV3 {
  (modelId: string): LanguageModelV3;
  languageModel(modelId: string): LanguageModelV3;
  chat(modelId: string): LanguageModelV3;
  embedding(modelId: string): EmbeddingModelV3;
  // ... other model type methods
  tools?: typeof providerSpecificTools; // custom tools
}

// 3. Factory Function (CRITICAL PATTERN)
export function createMyProvider(options: ProviderSettings = {}): MyProvider {
  // Load API key from options or environment
  const apiKey = loadApiKey({
    apiKey: options.apiKey,
    environmentVariableName: 'MYPROVIDER_API_KEY',
    description: 'MyProvider',
  });

  // Load optional settings
  const baseURL = withoutTrailingSlash(
    loadOptionalSetting({
      settingValue: options.baseURL,
      environmentVariableName: 'MYPROVIDER_BASE_URL',
    }),
  ) ?? 'https://api.myprovider.com/v1';

  // Create header factory function (called for each request)
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${apiKey}`,
        ...options.headers,
      },
      `ai-sdk/myprovider/${VERSION}`,
    );

  // Create model factories
  const createChatModel = (modelId: string) =>
    new MyChatLanguageModel(modelId, {
      provider: options.name ?? 'myprovider',
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // Create provider function
  const provider = function (modelId: string) {
    return createChatModel(modelId);
  };

  // Attach required properties
  provider.specificationVersion = 'v3' as const;
  provider.languageModel = (modelId) => createChatModel(modelId);
  provider.chat = createChatModel;
  // ... other model type methods

  return provider as MyProvider;
}

// 4. Default instance
export const myProvider = createMyProvider();
```

