  // Non-streaming generation
  async doGenerate(options: LanguageModelV3CallOptions): Promise<LanguageModelV3GenerateResult> {
    const { args: body, warnings } = await this.getArgs(options);

    const { responseHeaders, value: response, rawValue } = await postJsonToApi({
      url: this.config.url({ path: '/chat/completions', modelId: this.modelId }),
      headers: combineHeaders(this.config.headers(), options.headers),
      body,
      failedResponseHandler: myFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(myResponseSchema),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    return {
      content: [{ type: 'text', text: response.content }],
      finishReason: { unified: 'stop', raw: response.finishReason },
      usage: { inputTokens: response.usage.input, outputTokens: response.usage.output },
      request: { body },
      response: { headers: responseHeaders, body: rawValue },
      warnings,
      providerMetadata: { myprovider: {} },
    };
  }

  // Streaming generation
  async doStream(options: LanguageModelV3CallOptions): Promise<LanguageModelV3StreamResult> {
    const { args, warnings } = await this.getArgs(options);

    const body = { ...args, stream: true };

    const { responseHeaders, value: response } = await postJsonToApi({
      url: this.config.url({ path: '/chat/completions', modelId: this.modelId }),
