```typescript
export class MyEmbeddingModel implements EmbeddingModelV3 {
  readonly specificationVersion = 'v3';
  readonly modelId: string;
  readonly maxEmbeddingsPerCall = 2048; // API limit
  readonly supportsParallelCalls = true;

  private readonly config: OpenAIConfig;

  get provider(): string {
    return this.config.provider;
  }

  async doEmbed(options: EmbeddingModelV3CallOptions): Promise<EmbeddingModelV3Result> {
    if (options.values.length > this.maxEmbeddingsPerCall) {
      throw new TooManyEmbeddingValuesForCallError({
        provider: this.provider,
        modelId: this.modelId,
        maxEmbeddingsPerCall: this.maxEmbeddingsPerCall,
        values: options.values,
      });
    }

    const myOptions = await parseProviderOptions({
      provider: 'myprovider',
      providerOptions: options.providerOptions,
      schema: myEmbeddingOptions,
    }) ?? {};

    const { responseHeaders, value: response, rawValue } = await postJsonToApi({
      url: this.config.url({ path: '/embeddings', modelId: this.modelId }),
      headers: combineHeaders(this.config.headers(), options.headers),
      body: {
        model: this.modelId,
        input: options.values,
        // provider-specific options
        ...myOptions,
      },
      failedResponseHandler: myFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(myEmbeddingResponseSchema),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    return {
      warnings: [],
      embeddings: response.data.map(item => item.embedding),
      usage: response.usage ? { tokens: response.usage.prompt_tokens } : undefined,
      response: { headers: responseHeaders, body: rawValue },
    };
  }
}
