    modelId: this.modelId,
    headers: responseHeaders,
    body: rawValue,
  },
};
```

---

### WARNINGS & METADATA

#### **Warnings** (SharedV3Warning)
```typescript
warnings: [
  {
    type: 'unsupported',
    feature: 'topK',
    details: 'topK is not supported by this model',
  },
  {
    type: 'compatibility',
    feature: 'temperature',
    details: 'temperature is handled differently',
  },
  {
    type: 'other',
    message: 'Generic warning message',
  },
];
```

#### **Provider Metadata** (SharedV3ProviderMetadata)
```typescript
providerMetadata: {
  myprovider: {
    cacheControl: { type: 'ephemeral' },
    customField: 'value',
  },
};
```

---

### FETCH FUNCTION PATTERN

**Type:** `FetchFunction = typeof globalThis.fetch`

Allows custom fetch implementation (middleware, mocking, proxies):

```typescript
const customFetch: FetchFunction = async (url, options) => {
  console.log('Request:', url, options);
  const response = await globalThis.fetch(url, options);
  console.log('Response:', response.status);
  return response;
};

const provider = createMyProvider({
  fetch: customFetch,
});
```

---

### CAPABILITY DETECTION PATTERN

Providers can expose model capabilities for feature negotiation:

```typescript
function getMyModelCapabilities(modelId: string) {
  return {
    isReasoningModel: modelId.includes('reasoning'),
    supportsJsonOutput: true,
    supportsStreaming: true,
    supportsTools: true,
    supportsVision: modelId.includes('vision'),
  };
}

// Use in model:
const capabilities = getMyModelCapabilities(this.modelId);
if (capabilities.supportsVision) {
  // Handle vision
}
```

---

### FILE PATHS - IMPLEMENTATION CHECKLIST

For a new provider `@ai-sdk/myprovider`:

**Core Files:**
- `/packages/myprovider/src/index.ts` - Main export
- `/packages/myprovider/src/myprovider-provider.ts` - Factory function
- `/packages/myprovider/src/myprovider-config.ts` - Config type

**Language Model (if supported):**
- `/packages/myprovider/src/chat/myprovider-chat-language-model.ts`
- `/packages/myprovider/src/chat/myprovider-chat-options.ts`
- `/packages/myprovider/src/chat/myprovider-chat-api.ts` - API schemas

**Embedding Model (if supported):**
- `/packages/myprovider/src/embedding/myprovider-embedding-model.ts`
- `/packages/myprovider/src/embedding/myprovider-embedding-options.ts`
- `/packages/myprovider/src/embedding/myprovider-embedding-api.ts`

**Image Model (if supported):**
- `/packages/myprovider/src/image/myprovider-image-model.ts`
- `/packages/myprovider/src/image/myprovider-image-options.ts`
- `/packages/myprovider/src/image/myprovider-image-api.ts`

**Error Handling:**
- `/packages/myprovider/src/myprovider-error.ts` - Error schema & handler

**Utilities:**
- `/packages/myprovider/src/myprovider-config.ts` - Shared config type
- `/packages/myprovider/src/version.ts` - Version constant
- `/packages/myprovider/src/internal/index.ts` - Internal exports

**Testing & Config:**
- `/packages/myprovider/tsconfig.json` - TS config with provider/provider-utils references
- `/packages/myprovider/package.json` - Package definition
- Update root `/tsconfig.json` with `{ "path": "packages/myprovider" }`

---

### SUMMARY OF KEY PATTERNS

1. **Factory Pattern:** `createXxx(options)` returns provider instance with typed model methods
2. **Config Type:** Shared `XxxConfig` passed to all model classes with `provider`, `headers`, `url`, `fetch`
3. **Headers Factory:** `getHeaders() => Record<string, string>` called per request for dynamic headers
4. **Options Validation:** `lazySchema` + `zodSchema` + `parseProviderOptions` for provider-specific options
5. **Response Handlers:** Zod-based schemas for strict API response validation
6. **Error Handling:** Zod schema for error responses + `createJsonErrorResponseHandler`
7. **Streaming:** `TransformStream` to convert API event stream to SDK `LanguageModelV3StreamPart` stream
8. **Warnings:** Emit unsupported features via `SharedV3Warning[]`
9. **Metadata:** Include provider-specific data via `SharedV3ProviderMetadata`
10. **User Agent:** Always append SDK identifier via `withUserAgentSuffix`

All patterns are consistently applied across OpenAI, Anthropic, Google, and other existing providers.

