### Step 9: Create `packages/pixelart/src/pixelart-image-settings.ts`

Defines the model ID type and the provider-specific settings.

```ts
// Fictional PixelArt provider model IDs.
export type PixelArtImageModelId =
  | 'pixelart-standard'
  | 'pixelart-hd'
  | (string & {});

/**
 * The pixel art rendering style.
 *
 * - `pixel`: Classic pixel art with visible square pixels. Default.
 * - `retro`: Retro gaming style with limited color palette.
 * - `8bit`: 8-bit era style with characteristic constraints.
 */
export type PixelArtStyle = 'pixel' | 'retro' | '8bit';

/**
 * Configuration settings for PixelArt image generation.
 */
export interface PixelArtImageSettings {
  /**
   * The rendering style to use. Default is `pixel`.
   */
  style?: PixelArtStyle;

  /**
   * The pixel density of the generated image.
   * Higher values produce more detailed images with smaller pixels.
   * Range: 1 to 64. Default is determined by the model.
   */
  pixelDensity?: number;
}
```

