### Step 10: Create `packages/pixelart/src/pixelart-image-model.ts`

This is the core implementation. Unlike luma/black-forest-labs which use async polling, PixelArt uses a simpler synchronous API: POST returns base64 images directly. This makes the implementation significantly cleaner.

Key design decisions:
- Uses `postJsonToApi` for the API call to `POST {baseURL}/images/generations`
- Returns base64 strings (not binary Uint8Array) since the fictional API returns base64 directly
- Supports `n` (multiple images per call) since the API returns an array
- `maxImagesPerCall` set to 4 (fictional limit)
- Passes `size` directly to the API (unlike luma which does not support it)
- Passes `seed` directly to the API
- Provider options schema validates `style` and `pixelDensity`

```ts
import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  createJsonResponseHandler,
  createJsonErrorResponseHandler,
  postJsonToApi,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    // Parse and validate provider options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        prompt,
        model: this.modelId,
        n,
        ...(size != null ? { size } : {}),
        ...(seed != null ? { seed } : {}),
        ...(pixelArtOptions?.style != null
          ? { style: pixelArtOptions.style }
          : {}),
        ...(pixelArtOptions?.pixelDensity != null
          ? { pixel_density: pixelArtOptions.pixelDensity }
          : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: (error: PixelArtErrorData) =>
          error.error?.message ?? 'Unknown error',
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtResponseSchema,
      ),
    });

    return {
      images: response.data.map(
        (item: { b64_json: string }) => item.b64_json,
      ),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// Response schema: the API returns { data: [{ b64_json: "..." }, ...] }
const pixelArtResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

// Error schema: the API returns { error: { message: "...", type: "...", code: "..." } }
const pixelArtErrorSchema = z.object({
  error: z
    .object({
      message: z.string(),
      type: z.string().nullish(),
      code: z.string().nullish(),
    })
    .nullish(),
});

export type PixelArtErrorData = z.infer<typeof pixelArtErrorSchema>;

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The pixel art rendering style.
       * - `pixel`: Classic pixel art with visible square pixels. Default.
       * - `retro`: Retro gaming style with limited color palette.
       * - `8bit`: 8-bit era style with characteristic constraints.
       */
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),

      /**
       * The pixel density of the generated image.
       * Higher values produce more detailed images with smaller pixels.
       * Range: 1 to 64.
       */
      pixelDensity: z.number().int().min(1).max(64).nullish(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;
