export { createPixelArt, pixelart } from './pixelart-provider';
export type {
  PixelArtProvider,
  PixelArtProviderSettings,
} from './pixelart-provider';
export type {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';
export { VERSION } from './version';

import { ImageModelV3 } from '@ai-sdk/provider';
import {
  FetchFunction,
  loadApiKey,
  loadOptionalSetting,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import {
  PixelArtImageModelId,
  PixelArtImageSettings,
} from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProvider {
  /**
   * Creates a model for image generation.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Creates a model for image generation.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;
}

export interface PixelArtProviderSettings {
  /**
   * Base URL for the PixelArt API calls.
   *
   * @default 'https://api.pixelart.ai/v1'
   */
  baseURL?: string;

  /**
   * API key for authenticating requests.
   */
  apiKey?: string;

  /**
   * Custom headers to include in the requests.
   */
  headers?: Record<string, string>;

  /**
   * Provider name. Overrides the `pixelart` default name.
   */
  name?: string;

  /**
   * Custom fetch implementation. You can use it as a middleware to intercept
   * requests, or to provide a custom fetch implementation for e.g. testing.
   */
  fetch?: FetchFunction;

  /**
   * Image generation settings that apply to all image models created by this
   * provider instance.
   */
  imageSettings?: PixelArtImageSettings;
}

/**
 * Create a PixelArt provider instance.
 */
export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(
      loadOptionalSetting({
        settingValue: options.baseURL,
        environmentVariableName: 'PIXELART_BASE_URL',
      }),
    ) ?? 'https://api.pixelart.ai/v1';

  const providerName = options.name ?? 'pixelart';

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, options.imageSettings ?? {}, {
      provider: `${providerName}.image`,
      url: ({ path }) => `${baseURL}${path}`,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider: PixelArtProvider = {
    imageModel: createImageModel,
    image: createImageModel,
  };

  return provider;
}

/**
 * Default PixelArt provider instance.
 */
export const pixelart = createPixelArt();

